import{_ as s,o as t,c as a,a2 as i}from"./chunks/framework.C_beXv0I.js";const u=JSON.parse('{"title":"The four modes","description":"","frontmatter":{},"headers":[],"relativePath":"reference/modes.md","filePath":"reference/modes.md","lastUpdated":1783011651000}'),n={name:"reference/modes.md"};function o(r,e,h,d,l,p){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="the-four-modes" tabindex="-1">The four modes <a class="header-anchor" href="#the-four-modes" aria-label="Permalink to &quot;The four modes&quot;">​</a></h1><p>Muster exposes four entry points as slash commands under the <code>muster:</code> namespace.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Command</th><th>Shape</th></tr></thead><tbody><tr><td>Run</td><td><code>/muster:run &lt;outcome&gt;</code></td><td>Plan and show, then stop for approval</td></tr><tr><td>Autopilot</td><td><code>/muster:autopilot &lt;outcome&gt;</code></td><td>Hands-off full lifecycle</td></tr><tr><td>Diagnose</td><td><code>/muster:diagnose &lt;symptom&gt;</code></td><td>Failure-first single-bug fix</td></tr><tr><td>Audit</td><td><code>/muster:audit [path]</code></td><td>Breadth-first whole-codebase review and fix</td></tr></tbody></table><h2 id="run" tabindex="-1">Run <a class="header-anchor" href="#run" aria-label="Permalink to &quot;Run&quot;">​</a></h2><p>The interactive router. Its front half is an assess-then-interview step: <code>muster assess</code> does a deterministic gap-check on the outcome (too short, no success criteria, vague), and if the outcome is not clear, the interview skill runs an interactive requirements interview, one question at a time, behind an approval gate.</p><p>Then it detects, routes, and shows the glass-box crew manifest plus the plan, and <strong>stops</strong>. Run plans and shows; selecting Approve &amp; run chains into autopilot in-session, while Adjust and Cancel stay plan-only.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/muster:run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> limiting</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> public</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> API</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> with</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests</span></span></code></pre></div><p>Run and Autopilot both accept a GitHub issue reference (a bare number, <code>#123</code>, or an issues URL) as the outcome.</p><h2 id="autopilot" tabindex="-1">Autopilot <a class="header-anchor" href="#autopilot" aria-label="Permalink to &quot;Autopilot&quot;">​</a></h2><p>Runs the whole lifecycle hands-off: branch, detect, route, run waves (parallel fan-out, tournaments, an adversarial review gate), commit per wave, then present the merge decision. It only stops for that merge decision or for an escalation.</p><p>Tournaments synthesize rather than only pick one winner. The judge maps consensus, contradictions, partial coverage, and blind spots across candidates. <code>muster fuse</code> then either grafts the best of the top-K via a synthesizer (mode <code>fuse</code>) or falls back to the single best candidate (winner-take-all) when candidates already agree or only one passes.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/muster:autopilot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Resolve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> all</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> issues</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> and</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> README</span></span></code></pre></div><p>It triggers the interview only on an actual information gap. In unattended (Routine) mode it records the gap to the run report instead of blocking, and stops at a reviewable artifact (a pull request) rather than auto-merging.</p><h2 id="diagnose" tabindex="-1">Diagnose <a class="header-anchor" href="#diagnose" aria-label="Permalink to &quot;Diagnose&quot;">​</a></h2><p>Failure-first. Reproduce, find the root cause via systematic debugging on the best available debug provider, fix, add a regression test, verify. No symptom-patching.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/muster:diagnose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Paste</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> failing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> or</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stack</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> trace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> here</span></span></code></pre></div><h2 id="audit" tabindex="-1">Audit <a class="header-anchor" href="#audit" aria-label="Permalink to &quot;Audit&quot;">​</a></h2><p>The review-and-fix counterpart to diagnose. Where diagnose is one bug, audit sweeps the whole codebase. It fans out six read-only dimension reviews in parallel (architecture, tech-debt, coverage, simplification, readability, security), each on the best provider for its role, consolidates the findings into one ranked ledger, then fixes everything with TDD and verifies through the review gate before presenting the merge.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/muster:audit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/muster:audit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/payments</span></span></code></pre></div><p>Next: the <a href="/muster/reference/commands">CLI commands</a> that power these modes.</p>`,20)])])}const k=s(n,[["render",o]]);export{u as __pageData,k as default};
